function makeAddrAndKey(string memory name) internal virtual returns (address addr, uint256 privateKey) {
    privateKey = uint256(keccak256(abi.encodePacked(name)));
    addr = vm.addr(privateKey);
    vm.label(addr, name);
}

function testZeroFloorSub(uint256 x, uint256 y) public {
    assertEq(UtilsLib.zeroFloorSub(x, y), x < y ? 0 : x - y);
}

function _efficientHash(bytes32 a, bytes32 b) internal pure returns (bytes32 hash) {
    assembly ("memory-safe") {
        mstore(0x00, a)
        mstore(0x20, b)
        hash := keccak256(0x00, 0x40)
    }
}

function bound(uint256 x, uint256 min, uint256 max) internal pure virtual returns (uint256 result) {
    result = _bound(x, min, max);
}

function hoax(address msgSender) internal virtual {
    vm.deal(msgSender, 1 << 128);
    vm.prank(msgSender);
}

function failed() public view returns (bool) {
    if (_failed) {
        return true;
    } else {
        return vm.load(address(vm), _FAILED_SLOT) != bytes32(0);
    }
}

function assert_ftl_invariant_A(address loan) internal {
    assertGe(collateralAsset.balanceOf(loan), IFixedTermLoan(loan).collateral(), "Loan Invariant A");
}

function assert_ftl_invariant_B(address loan) internal {
    assertGe(fundsAsset.balanceOf(loan), IFixedTermLoan(loan).drawableFunds(), "Loan Invariant B");
}

function _divRoundUp(uint256 numerator_, uint256 divisor_) internal pure returns (uint256 result_) {
    result_ = (numerator_ + divisor_ - 1) / divisor_;
}

function test_setManualWithdrawal_failIfLpAlreadyInQueue() external {
    requestRedeem(lp, 1_000e6);

    vm.expectRevert("WM:SMW:IN_QUEUE");
    vm.prank(poolDelegate);
    queueWM.setManualWithdrawal(lp, true);
}

function test_setManualWithdrawal_failIfProtocolIsPaused() external {
    vm.prank(governor);
    globals.setProtocolPause(true);

    vm.expectRevert("WM:PAUSED");
    vm.prank(poolDelegate);
    queueWM.setManualWithdrawal(lp, true);
}

function run() public returns (IPoolManager manager) {
    vm.startBroadcast();

    manager = new PoolManager(address(this));
    console2.log("PoolManager", address(manager));

    vm.stopBroadcast();
}

for (uint256 i = 0; i < chains.length; i++) {
    uint256 chainId = chains[i];
    uint256 forkId = vm.createFork(config.getRpcUrl(chainId));
    forkOf[chainId] = forkId;
    chainIds.push(chainId);
}

function _requireSuccessfulContractCreation(address newContract) internal view {
    if (newContract == address(0) || newContract.code.length == 0) {
        revert FailedContractCreation({emitter: _SELF});
    }
}

function addCarry(uint256 x, uint256 y) internal pure returns (uint256 remainder, uint256 carry) {
    unchecked {
        remainder = x + y;
    }
    carry = remainder < x ? 1 : 0;
}

function calculatePortion(uint256 amount, uint256 bips) internal pure returns (uint256) {
    if (bips > BPS_DENOMINATOR) revert InvalidBips();
    return (amount * bips) / BPS_DENOMINATOR;
}

function assumeNotForgeAddress(address addr) internal pure virtual {
    // vm, console, and Create2Deployer addresses
    vm.assume(
        addr != address(vm) && addr != 0x000000000000000000636F6e736F6c652e6c6f67
            && addr != 0x4e59b44847b379578588920cA78FbF26c0B4956C
    );
}

function statefulFuzz_EtherBalance() external view {
    assertEq(createXAddr.balance, createXHandler.updatedBalance(), "100");
}

modifier whenTheNonceValueDoesNotExceed18446744073709551614(address deployer, uint64 nonce) {
    vm.assume(nonce < type(uint64).max);
    if (deployer.code.length != 0) {
        vm.assume(nonce != 0);
    }
    vm.setNonceUnsafe(deployer, nonce);
    _;
}

function test_RevertWhen_SenderNotMatch() external whenNoDelegateCall givenNotNull givenNotVoided {
    vm.expectRevert(abi.encodeWithSelector(Errors.SablierFlow_NotStreamSender.selector, users.eve, users.sender));
    flow.deposit(defaultStreamId, DEPOSIT_AMOUNT_6D, users.eve, users.recipient);
}

function test_fuzz_reasonableScoreNeverReverts(address test) public pure {
    uint256 score = VanityAddressLib.score(address(test));
    assertGe(score, 0);
    assertLe(score, 444);
}

function test_RevertWhen_DelegateCall() external {
    bytes memory callData = abi.encodeCall(flow.pause, (defaultStreamId));
    expectRevert_DelegateCall(callData);
}

function test_RevertGiven_Null() external whenNoDelegateCall {
    bytes memory callData = abi.encodeCall(flow.pause, (nullStreamId));
    expectRevert_Null(callData);
}

function bytesToUint(bytes memory b) internal pure virtual returns (uint256) {
    require(b.length <= 32, "StdUtils bytesToUint(bytes): Bytes length exceeds 32.");
    return abi.decode(abi.encodePacked(new bytes(32 - b.length), b), (uint256));
}

setupFees({
    delegateOriginationFee:     500e6,
    delegateServiceFee:         300e6,
    delegateManagementFeeRate:  0.02e6,
    platformOriginationFeeRate: 0.001e6,
    platformServiceFeeRate:     0.005e6,  // 10k after 1m seconds
    platformManagementFeeRate:  0.08e6
});

function tryBlockAndAggregate(bool requireSuccess, Call[] calldata calls) public payable returns (uint256 blockNumber, bytes32 blockHash, Result[] memory returnData) {
    blockNumber = block.number;
    blockHash = blockhash(block.number);
    returnData = tryAggregate(requireSuccess, calls);
}

